/**
 * @file vfft_wisdom.h
 * @brief VectorFFT wisdom — cached optimal factorizations
 *
 * Wisdom file format (text):
 *   # VectorFFT wisdom — generated by bench_factorize
 *   # ISA: AVX2 | AVX512 | SCALAR
 *   N factor1 factor2 ... factorK
 *   N factor1 factor2 ... factorK
 *
 * Example:
 *   # VectorFFT wisdom — generated by bench_factorize
 *   # ISA: AVX2
 *   1024 16 16 4
 *   4096 16 16 16
 *   8192 16 16 32
 *
 * Usage:
 *   vfft_wisdom wis;
 *   vfft_wisdom_init(&wis);
 *   vfft_wisdom_load(&wis, "vfft_wisdom.txt");
 *   // ... pass to planner ...
 *   vfft_wisdom_destroy(&wis);
 */

#ifndef VFFT_WISDOM_H
#define VFFT_WISDOM_H

/* Silence MSVC/clang-cl deprecation warnings for fopen/strtok/sscanf */
#if defined(_MSC_VER) || defined(_WIN32)
#ifndef _CRT_SECURE_NO_WARNINGS
#define _CRT_SECURE_NO_WARNINGS
#endif
#endif

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define VFFT_WISDOM_MAX_FACTORS 32
#define VFFT_WISDOM_MAX_ENTRIES 1024

typedef struct
{
    size_t N;
    size_t factors[VFFT_WISDOM_MAX_FACTORS];
    size_t nfactors;
    double ns; /* benchmark time (informational, not used by planner) */
} vfft_wisdom_entry;

typedef struct
{
    vfft_wisdom_entry entries[VFFT_WISDOM_MAX_ENTRIES];
    size_t count;
} vfft_wisdom;

static inline void vfft_wisdom_init(vfft_wisdom *w)
{
    memset(w, 0, sizeof(*w));
}

static inline void vfft_wisdom_destroy(vfft_wisdom *w)
{
    w->count = 0;
}

/** Look up optimal factorization for N. Returns NULL if not found. */
static inline const vfft_wisdom_entry *vfft_wisdom_lookup(
    const vfft_wisdom *w, size_t N)
{
    if (!w)
        return NULL;
    for (size_t i = 0; i < w->count; i++)
    {
        if (w->entries[i].N == N)
            return &w->entries[i];
    }
    return NULL;
}

/** Add or update an entry. */
static inline void vfft_wisdom_set(
    vfft_wisdom *w, size_t N,
    const size_t *factors, size_t nfactors, double ns)
{
    /* Update existing */
    for (size_t i = 0; i < w->count; i++)
    {
        if (w->entries[i].N == N)
        {
            w->entries[i].nfactors = nfactors;
            memcpy(w->entries[i].factors, factors, nfactors * sizeof(size_t));
            w->entries[i].ns = ns;
            return;
        }
    }
    /* Add new */
    if (w->count < VFFT_WISDOM_MAX_ENTRIES)
    {
        vfft_wisdom_entry *e = &w->entries[w->count++];
        e->N = N;
        e->nfactors = nfactors;
        memcpy(e->factors, factors, nfactors * sizeof(size_t));
        e->ns = ns;
    }
}

/** Save wisdom to file. */
static inline int vfft_wisdom_save(const vfft_wisdom *w, const char *path)
{
    FILE *f = fopen(path, "w");
    if (!f)
        return -1;

    fprintf(f, "# VectorFFT wisdom — generated by bench_factorize\n");
    fprintf(f, "# ISA: ");
#if defined(__AVX512F__)
    fprintf(f, "AVX512\n");
#elif defined(__AVX2__)
    fprintf(f, "AVX2\n");
#else
    fprintf(f, "SCALAR\n");
#endif
    fprintf(f, "# Format: N factor1 factor2 ... [ns=time]\n");

    for (size_t i = 0; i < w->count; i++)
    {
        const vfft_wisdom_entry *e = &w->entries[i];
        fprintf(f, "%zu", e->N);
        for (size_t j = 0; j < e->nfactors; j++)
            fprintf(f, " %zu", e->factors[j]);
        if (e->ns > 0)
            fprintf(f, " [ns=%.0f]", e->ns);
        fprintf(f, "\n");
    }

    fclose(f);
    return 0;
}

/** Load wisdom from file. Appends to existing entries. */
static inline int vfft_wisdom_load(vfft_wisdom *w, const char *path)
{
    FILE *f = fopen(path, "r");
    if (!f)
        return -1;

    char line[512];
    while (fgets(line, sizeof(line), f))
    {
        /* Skip comments and empty lines */
        if (line[0] == '#' || line[0] == '\n' || line[0] == '\r')
            continue;

        /* Parse: N f1 f2 f3 ... [ns=xxx] */
        size_t N = 0, factors[VFFT_WISDOM_MAX_FACTORS], nf = 0;
        double ns = 0;

        char *tok = strtok(line, " \t\n\r");
        if (!tok)
            continue;
        N = (size_t)atol(tok);
        if (N == 0)
            continue;

        while ((tok = strtok(NULL, " \t\n\r")) != NULL)
        {
            /* Check for [ns=xxx] annotation */
            if (tok[0] == '[')
            {
                if (sscanf(tok, "[ns=%lf]", &ns) == 1)
                    ; /* parsed */
                break;
            }
            if (nf < VFFT_WISDOM_MAX_FACTORS)
                factors[nf++] = (size_t)atol(tok);
        }

        /* Verify product */
        if (nf > 0)
        {
            size_t prod = 1;
            for (size_t j = 0; j < nf; j++)
                prod *= factors[j];
            if (prod == N)
                vfft_wisdom_set(w, N, factors, nf, ns);
        }
    }

    fclose(f);
    return 0;
}

/** Print wisdom contents to stdout. */
static inline void vfft_wisdom_print(const vfft_wisdom *w)
{
    printf("  Wisdom: %zu entries\n", w->count);
    for (size_t i = 0; i < w->count; i++)
    {
        const vfft_wisdom_entry *e = &w->entries[i];
        printf("    N=%-8zu ", e->N);
        for (size_t j = 0; j < e->nfactors; j++)
        {
            if (j)
                printf("x");
            printf("%zu", e->factors[j]);
        }
        if (e->ns > 0)
            printf("  (%.0f ns)", e->ns);
        printf("\n");
    }
}

#endif /* VFFT_WISDOM_H */